import org.owasp.encoder.Encode;

public class XssSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encoding user input before including it in the HTML response
        String encodedUserInput = Encode.forHtml(userInput);

        System.out.println("<html>");
        System.out.println("<head><title>XSS Secure Example</title></head>");
        System.out.println("<body>");
        System.out.println("User Input: " + encodedUserInput);
        System.out.println("</body>");
        System.out.println("</html>");
    }
}

